    P(M1);           // 申请 R1
    P(M2);           // 申请 R2
    使用 R1 和 R2;
    V(M2);
    V(M1);
}

// P2（按相同顺序申请）
void P2() {
    P(M1);           // 先申请 R1，后申请 R2
    P(M2);
    使用 R1 和 R2;
    V(M2);
    V(M1);
}
```

